<span class="line"><span style="color:#ABB2BF;">                                 (Alias: </span><span style="color:#FFFFFF;">--</span><span style="color:#ABB2BF;">no</span><span style="color:#56B6C2;">-</span><span style="color:#ABB2BF;">abort</span><span style="color:#56B6C2;">-</span><span style="color:#ABB2BF;">on</span><span style="color:#56B6C2;">-</span><span style="color:#ABB2BF;">unavailable</span><span style="color:#56B6C2;">-</span><span style="color:#ABB2BF;">fragment)</span></span>
